import { useEffect, useState } from 'react';

function readShellPathname(): string {
  if (typeof window === 'undefined') return '/';
  const path = window.location.pathname || '/';
  return path.endsWith('/') && path.length > 1 ? path.slice(0, -1) : path;
}

/**
 * Shell URL pathname — SSOT for Nav parcel (not React Router inside Nav).
 * single-spa navigateToUrl updates window.location; Nav's BrowserRouter does not.
 */
export function useShellPathname(): string {
  const [pathname, setPathname] = useState(readShellPathname);

  useEffect(() => {
    const sync = () => {
      const next = readShellPathname();
      setPathname((prev) => (prev === next ? prev : next));
    };

    window.addEventListener('single-spa:routing-event', sync);
    window.addEventListener('popstate', sync);
    sync();

    return () => {
      window.removeEventListener('single-spa:routing-event', sync);
      window.removeEventListener('popstate', sync);
    };
  }, []);

  return pathname;
}
