import type { NavMenuItemDto } from '../hooks/useUserPermissions';

/** Merge lazy-loaded nav rows by stable menu code. */
export function mergeNavItems(
  base: NavMenuItemDto[] | undefined,
  extra: NavMenuItemDto[],
): NavMenuItemDto[] {
  const map = new Map<string, NavMenuItemDto>();
  for (const item of base ?? []) map.set(item.code, item);
  for (const item of extra) map.set(item.code, item);
  return [...map.values()];
}
