import type { NavMenuItemDto } from '../hooks/useUserPermissions';
import { normalizeNavPath } from './resolveNavTitle';

/**
 * Sidebar logo click target — must be an allowed menu path, not bare `/` (Home MFE empty shell).
 * Priority: packageDefaultUrl → admin fallback → first nav leaf → /dashboard.
 */
export function resolveLogoHomePath(
  pathname: string,
  navItems: NavMenuItemDto[] | undefined,
  packageDefaultUrl?: string | null,
): string {
  const pkg = packageDefaultUrl?.trim();
  if (pkg) return normalizeNavPath(pkg);

  if (pathname.startsWith('/admin')) return '/admin/accounts';

  const leaves = (navItems ?? [])
    .filter((i) => !i.isGroup && i.path && i.path !== '#')
    .sort((a, b) => a.orderIndex - b.orderIndex);
  if (leaves[0]?.path) return normalizeNavPath(leaves[0].path);

  return '/dashboard';
}
